mod cli;

use cli::{
    Cli, Commands, FacetAction, ManifestAction, MarketplaceAction, PluginAction, RecipeAction,
};

fn main() -> Result<()> {
    let cli = Cli::parse();
    let fs = RealFilesystem;
    let cwd = env::current_dir()?;
    let root = detect_repo(&cwd, &fs)?;

    match cli.command {
        Commands::Facet { action } => handle_facet(&action, &root, &fs)?,
        Commands::Recipe { action } => handle_recipe(action, &root, &fs)?,
        Commands::Plugin { action } => handle_plugin(&action, &root, &fs)?,
        Commands::Manifest { action } => handle_manifest(&action, &root, &fs)?,
        Commands::Marketplace { action } => handle_marketplace(&action, &root, &fs)?,
        Commands::Validate => {
            let issues = validate_all(&root, &fs)?;
            print!("{}", format_validation_issues(&issues));
        }
        Commands::Status => {
            print!("{}", format_status(&root, &fs)?);
        }
    }

    Ok(())
}

fn handle_facet(action: &FacetAction, root: &RepoRoot, fs: &dyn Filesystem) -> Result<()> {
    match action {
        FacetAction::List => {
            let facets = scan_facets(root, fs)?;
            print!("{}", format_facet_list(&facets));
            let recipes = scan_recipes(root, fs)?;
            print!("{}", format_recipe_list(&recipes));
        }
        FacetAction::Validate => {
            let issues = validate_facets(root, fs)?;
            print!("{}", format_validation_issues(&issues));
        }
    }
    Ok(())
}

fn handle_recipe(action: RecipeAction, root: &RepoRoot, fs: &dyn Filesystem) -> Result<()> {
    match action {
        RecipeAction::List => {
            let recipes = scan_recipes(root, fs)?;
            print!("{}", format_recipe_list(&recipes));
        }
        RecipeAction::Assemble { name, all } => {
            let recipes = scan_recipes(root, fs)?;
            if all {
                for recipe in &recipes {
                    let content = assemble_recipe(recipe, root, fs)?;
                    write_assembled(recipe, &content, root, fs)?;
                    println!("Wrote {}", recipe.produces);
                }
                println!("Assembled {} recipe(s)", recipes.len());
            } else if let Some(name) = name {
                let recipe = find_recipe(&recipes, &name)?;
                let content = assemble_recipe(recipe, root, fs)?;
                write_assembled(recipe, &content, root, fs)?;
                println!("Wrote {}", recipe.produces);
            } else {
                anyhow::bail!("Provide a recipe name or use --all");
            }
        }
        RecipeAction::Diff { name } => {
            let recipes = scan_recipes(root, fs)?;
            let recipe = find_recipe(&recipes, &name)?;
            let diff = diff_recipe(recipe, root, fs)?;
            if diff.is_empty() {
                println!("Recipe '{}' is up to date", recipe.name);
            } else {
                println!("{diff}");
            }
        }
    }
    Ok(())
}

fn find_recipe<'a>(
    recipes: &'a [cmf::facet_types::Recipe],
    name: &str,
) -> Result<&'a cmf::facet_types::Recipe> {
    recipes
        .iter()
        .find(|r| r.name == name)
        .ok_or_else(|| anyhow::anyhow!("Recipe '{name}' not found"))
}

fn handle_plugin(action: &PluginAction, root: &RepoRoot, fs: &dyn Filesystem) -> Result<()> {
    match action {
        PluginAction::Init { name } => {
            let path = init_plugin(root, name, fs)?;
            println!("Created plugin '{}' at {}", name, path.display());
        }
        PluginAction::Validate => {
            let issues = validate_all_plugins(root, fs)?;
            print!("{}", format_validation_issues(&issues));
        }
        PluginAction::List => {
            let plugins = scan_plugins(root, fs)?;
            print!("{}", format_plugin_list(&plugins));
        }
    }
    Ok(())
}

fn handle_manifest(action: &ManifestAction, root: &RepoRoot, fs: &dyn Filesystem) -> Result<()> {
    match action {
        ManifestAction::Generate => {
            let written = generate_manifests(root, fs)?;
            print!("{}", format_manifest_summary(&written));
        }
    }
    Ok(())
}

fn handle_marketplace(
    action: &MarketplaceAction,
    root: &RepoRoot,
    fs: &dyn Filesystem,
) -> Result<()> {
    match action {
        MarketplaceAction::Validate => {
            let issues = validate_marketplace(root, fs)?;
            print!("{}", format_validation_issues(&issues));
        }
        MarketplaceAction::Generate => {
            generate_marketplace(root, fs)?;
        }
    }
    Ok(())
}

use std::path::PathBuf;

use anyhow::Result;
use cmx::gateway::Filesystem;

use crate::repo::RepoRoot;

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum Platform {
    Claude,
    Codex,
    Cursor,
    Gemini,
}

impl Platform {
    /// The directory name for this platform's plugin manifest.
    pub fn manifest_dir(&self) -> &str {
        match self {
            Self::Claude => ".claude-plugin",
            Self::Codex => ".codex-plugin",
            Self::Cursor => ".cursor-plugin",
            Self::Gemini => ".gemini-plugin",
        }
    }

    /// All non-Claude platforms that we generate for.
    pub fn targets() -> &'static [Platform] {
        &[Self::Codex, Self::Cursor, Self::Gemini]
    }
}

/// Generate multi-platform manifests from the canonical `.claude-plugin/` source.
///
/// Works at both marketplace level (root `marketplace.json`) and per-plugin level
/// (`plugin.json`). Returns the list of files that were written.
pub fn generate_manifests(root: &RepoRoot, fs: &dyn Filesystem) -> Result<Vec<PathBuf>> {
    let mut written = Vec::new();

    // Collect all source files to replicate: (source_path, containing_dir)
    // where containing_dir is the parent of `.claude-plugin/`
    let mut sources: Vec<(PathBuf, PathBuf)> = Vec::new();

    // Root-level marketplace.json
    let root_marketplace = root.path.join(".claude-plugin").join("marketplace.json");
    if fs.exists(&root_marketplace) {
        sources.push((root_marketplace, root.path.clone()));
    }

    // Root-level plugin.json (for single-plugin repos)
    let root_plugin = root.path.join(".claude-plugin").join("plugin.json");
    if fs.exists(&root_plugin) {
        sources.push((root_plugin, root.path.clone()));
    }

    // Per-plugin plugin.json files under plugins/
    let plugins_dir = root.path.join("plugins");
    if fs.is_dir(&plugins_dir) {
        if let Ok(entries) = fs.read_dir(&plugins_dir) {
            for entry in entries {
                if !entry.is_dir {
                    continue;
                }
                let plugin_json = entry.path.join(".claude-plugin").join("plugin.json");
                if fs.exists(&plugin_json) {
                    sources.push((plugin_json, entry.path.clone()));
                }
            }
        }
    }

    // For each source file, copy to each target platform directory
    for (source_path, containing_dir) in &sources {
        let content = fs.read_to_string(source_path)?;
        let file_name = source_path
            .file_name()
            .expect("source path should have a file name")
            .to_string_lossy();

        for platform in Platform::targets() {
            let target_dir = containing_dir.join(platform.manifest_dir());
            fs.create_dir_all(&target_dir)?;

            let target_path = target_dir.join(file_name.as_ref());
            fs.write(&target_path, &content)?;
            written.push(target_path);
        }
    }

    Ok(written)
}

/// Format a summary of what was generated.
pub fn format_manifest_summary(files: &[PathBuf]) -> String {
    use std::fmt::Write as FmtWrite;

    if files.is_empty() {
        return "No .claude-plugin/ sources found — nothing to generate.\n".to_string();
    }

    let mut out = format!("Generated manifests for {} platforms:\n", Platform::targets().len());

    for platform in Platform::targets() {
        let dir_name = platform.manifest_dir();

        let platform_files: Vec<_> = files
            .iter()
            .filter(|p| p.components().any(|c| c.as_os_str() == dir_name))
            .collect();

        let marketplace_count =
            platform_files.iter().filter(|p| p.ends_with("marketplace.json")).count();
        let plugin_count = platform_files.iter().filter(|p| p.ends_with("plugin.json")).count();

        let mut parts = Vec::new();
        if marketplace_count > 0 {
            parts.push("marketplace.json".to_string());
        }
        if plugin_count > 0 {
            parts.push(format!(
                "{plugin_count} plugin manifest{}",
                if plugin_count == 1 { "" } else { "s" }
            ));
        }

        let _ = writeln!(out, "  {dir_name}/ — {}", parts.join(" + "));
    }

    out
}

