#[cfg(test)]
mod tests {
    use super::*;
    use crate::gateway::fakes::FakeFilesystem;
    use crate::test_support::{make_lock_entry_with_checksum, test_paths};
    use crate::types::ArtifactKind;

    fn agent_path(paths: &crate::paths::ConfigPaths) -> std::path::PathBuf {
        ArtifactKind::Agent
            .installed_path("my-agent", &paths.install_dir(ArtifactKind::Agent, false))
    }

    #[test]
    fn is_locally_modified_returns_false_when_checksum_matches() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();

        let content = "---\nname: my-agent\ndescription: test\n---\n";
        let path = agent_path(&paths);
        fs.add_file(path.clone(), content);

        // Compute the real checksum
        let cs = checksum_file_with(&path, &fs).unwrap();
        let mut entry = make_lock_entry_with_checksum(
            ArtifactKind::Agent,
            Some("1.0.0"),
            "source",
            "my-agent.md",
            &cs,
        );
        // Override installed_checksum to match current disk content
        entry.installed_checksum = cs;

        let modified = is_locally_modified(&path, ArtifactKind::Agent, &entry, &fs).unwrap();
        assert!(!modified, "expected not modified when checksum matches");
    }

    #[test]
    fn is_locally_modified_returns_true_when_checksum_differs() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();

        let path = agent_path(&paths);
        fs.add_file(path.clone(), "current content on disk");

        let mut entry = make_lock_entry_with_checksum(
            ArtifactKind::Agent,
            Some("1.0.0"),
            "source",
            "my-agent.md",
            "sha256:placeholder",
        );
        entry.installed_checksum = "sha256:different_from_disk".to_string();

        let modified = is_locally_modified(&path, ArtifactKind::Agent, &entry, &fs).unwrap();
        assert!(modified, "expected modified when checksum differs");
    }

    #[test]
    fn current_checksum_if_modified_returns_none_when_unchanged() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();

        let content = "---\nname: my-agent\ndescription: test\n---\n";
        let path = agent_path(&paths);
        fs.add_file(path.clone(), content);

        let cs = checksum_file_with(&path, &fs).unwrap();
        let mut entry = make_lock_entry_with_checksum(
            ArtifactKind::Agent,
            Some("1.0.0"),
            "source",
            "my-agent.md",
            &cs,
        );
        entry.installed_checksum = cs;

        let (modified, disk_cs) =
            current_checksum_if_modified(&path, ArtifactKind::Agent, &entry, &fs).unwrap();
        assert!(!modified, "expected not modified");
        assert!(disk_cs.is_none(), "expected no disk checksum when unchanged");
    }

    #[test]
    fn current_checksum_if_modified_returns_some_when_changed() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();

        let path = agent_path(&paths);
        fs.add_file(path.clone(), "modified content");

        let mut entry = make_lock_entry_with_checksum(
            ArtifactKind::Agent,
            Some("1.0.0"),
            "source",
            "my-agent.md",
            "sha256:placeholder",
        );
        entry.installed_checksum = "sha256:original_recorded_checksum".to_string();

        let (modified, disk_cs) =
            current_checksum_if_modified(&path, ArtifactKind::Agent, &entry, &fs).unwrap();
        assert!(modified, "expected modified");
        assert!(disk_cs.is_some(), "expected disk checksum to be present");
        assert!(
            disk_cs.unwrap().starts_with("sha256:"),
            "disk checksum should be a sha256 value"
        );
    }
}

use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(
    name = "cmx",
    about = "Package manager for curated agentic context — agents and skills",
    version
)]
pub struct Cli {
    #[command(subcommand)]
    pub command: Commands,
}

#[derive(Subcommand)]
pub enum Commands {
    /// Manage source repositories
    Source {
        #[command(subcommand)]
        action: SourceAction,
    },
    /// Manage agents
    Agent {
        #[command(subcommand)]
        action: ArtifactAction,
    },
    /// Manage skills
    Skill {
        #[command(subcommand)]
        action: ArtifactAction,
    },
    /// List all installed agents and skills
    List,
    /// Show installed artifacts that have updates available
    Outdated,
    /// Search all sources for agents and skills by keyword
    Search {
        /// Keyword to search for in artifact names and descriptions
        query: String,
    },
    /// Show detailed metadata for an installed artifact
    Info {
        /// Artifact name
        name: String,
    },
    /// View or modify cmx configuration
    Config {
        #[command(subcommand)]
        action: ConfigAction,
    },
}

#[derive(Subcommand)]
pub enum SourceAction {
    /// Register a source repository (local path or git URL)
    Add {
        /// Name to identify this source
        name: String,
        /// Local path or URL to the source repository
        path_or_url: String,
    },
    /// List registered sources
    List,
    /// Show available agents and skills in a source
    Browse {
        /// Name of the source to browse
        name: String,
    },
    /// Fetch latest changes for git-backed sources
    Update {
        /// Name of a specific source to update (default: all)
        name: Option<String>,
    },
    /// Unregister a source (does not delete artifacts)
    Remove {
        /// Name of the source to remove
        name: String,
    },
}

#[derive(Subcommand)]
pub enum ArtifactAction {
    /// Install an artifact from a source
    Install {
        /// Artifact name, or source:name to pin to a specific source
        name: Option<String>,
        /// Install all available artifacts from sources
        #[arg(long, conflicts_with = "name")]
        all: bool,
        /// Install into the current project instead of globally
        #[arg(long)]
        local: bool,
        /// Force overwrite even if locally modified
        #[arg(long)]
        force: bool,
    },
    /// List installed artifacts
    List,
    #[cfg(feature = "llm")]
    /// Compare installed artifact with source version using LLM analysis
    Diff {
        /// Artifact name
        name: String,
    },
    /// Update an installed artifact from its source
    Update {
        /// Artifact name
        name: Option<String>,
        /// Update all tracked artifacts
        #[arg(long, conflicts_with = "name")]
        all: bool,
        /// Force overwrite even if locally modified
        #[arg(long)]
        force: bool,
    },
    /// Uninstall an installed artifact
    Uninstall {
        /// Artifact name
        name: String,
        /// Uninstall from project scope instead of global
        #[arg(long)]
        local: bool,
    },
}

#[derive(Subcommand)]
pub enum ConfigAction {
    /// Show current configuration
    Show,
    /// Set LLM gateway (openai or ollama)
    Gateway {
        /// Gateway type: openai or ollama
        value: String,
    },
    /// Set LLM model name
    Model {
        /// Model name (e.g. gpt-5.4, qwen3.5:27b)
        value: String,
    },
}

