#[cfg(test)]
mod tests {
    use super::*;
    use crate::gateway::fakes::FakeFilesystem;
    use crate::test_support::{sample_lock_file, test_paths};
    use std::path::PathBuf;

    // --- load_from_with ---

    #[test]
    fn load_from_returns_empty_when_path_absent() {
        let fs = FakeFilesystem::new();
        let lock = load_from_with(Path::new("/nonexistent/cmx-lock.json"), &fs).unwrap();
        assert!(lock.packages.is_empty());
        assert_eq!(lock.version, 1);
    }

    #[test]
    fn load_from_parses_valid_json() {
        let fs = FakeFilesystem::new();
        let path = PathBuf::from("/config/cmx-lock.json");
        let json = serde_json::to_string(&sample_lock_file()).unwrap();
        fs.add_file(path.clone(), json);
        let lock = load_from_with(&path, &fs).unwrap();
        assert!(lock.packages.contains_key("my-agent"));
    }

    #[test]
    fn load_from_returns_error_on_malformed_json() {
        let fs = FakeFilesystem::new();
        let path = PathBuf::from("/config/cmx-lock.json");
        fs.add_file(path.clone(), "not json");
        assert!(load_from_with(&path, &fs).is_err());
    }

    // --- save_to_with ---

    #[test]
    fn save_to_creates_parent_dirs_and_writes() {
        let fs = FakeFilesystem::new();
        let path = PathBuf::from("/config/context-mixer/cmx-lock.json");
        save_to_with(&sample_lock_file(), &path, &fs).unwrap();
        assert!(fs.file_exists(&path));
    }

    // --- find_entry_with ---

    #[test]
    fn find_entry_returns_none_when_absent_in_both_scopes() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let result = find_entry_with("missing", &fs, &paths).unwrap();
        assert!(result.is_none());
    }

    #[test]
    fn find_entry_finds_entry_in_global_scope() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let lock = sample_lock_file();
        save_with(&lock, false, &fs, &paths).unwrap();

        let result = find_entry_with("my-agent", &fs, &paths).unwrap();
        assert!(result.is_some());
        let (_, local) = result.unwrap();
        assert!(!local, "expected global scope (local=false)");
    }

    #[test]
    fn find_entry_finds_entry_in_local_scope() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let lock = sample_lock_file();
        save_with(&lock, true, &fs, &paths).unwrap();

        let result = find_entry_with("my-agent", &fs, &paths).unwrap();
        assert!(result.is_some());
        let (_, local) = result.unwrap();
        assert!(local, "expected local scope (local=true)");
    }

    #[test]
    fn find_entry_prefers_global_when_present_in_both_scopes() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let lock = sample_lock_file();
        save_with(&lock, false, &fs, &paths).unwrap();
        save_with(&lock, true, &fs, &paths).unwrap();

        let result = find_entry_with("my-agent", &fs, &paths).unwrap();
        let (_, local) = result.unwrap();
        assert!(!local, "expected global to be preferred over local");
    }

    // --- round-trip via load_with / save_with ---

    #[test]
    fn save_and_load_with_round_trip() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let lock = sample_lock_file();
        save_with(&lock, false, &fs, &paths).unwrap();
        let loaded = load_with(false, &fs, &paths).unwrap();
        assert_eq!(loaded.packages.len(), 1);
        let entry = loaded.packages.get("my-agent").unwrap();
        assert_eq!(entry.version.as_deref(), Some("1.0.0"));
        assert_eq!(entry.source_checksum, "sha256:abc123");
    }

    // --- failure-path tests ---

    #[test]
    fn save_lock_returns_error_with_context_when_write_fails() {
        let fs = FakeFilesystem::new();
        let paths = test_paths();
        let lock_path = paths.lock_path(false);

        // Cause the write to the lock file path to fail
        fs.set_fail_on_write(lock_path);

        let lock = sample_lock_file();
        let result = save_with(&lock, false, &fs, &paths);
        assert!(result.is_err(), "expected Err when lock file write fails");

        let msg = result.unwrap_err().to_string();
        assert!(msg.contains("Failed to write"), "expected 'Failed to write' in error: {msg}");
    }
}

use anyhow::{Result, bail};
use clap::Parser;

use cmx::cli::{ArtifactAction, Cli, Commands, ConfigAction, SourceAction};
use cmx::context::AppContext;
use cmx::gateway::real::{RealFilesystem, RealGitClient, SystemClock};
use cmx::paths::ConfigPaths;
use cmx::types::ArtifactKind;

fn main() -> Result<()> {
    let cli = Cli::parse();
    let paths = ConfigPaths::from_env()?;

    let ctx = AppContext {
        fs: &RealFilesystem,
        git: &RealGitClient,
        clock: &SystemClock,
        paths: &paths,
        llm: None,
    };

    match cli.command {
        Commands::Source { action } => handle_source(action, &paths, &ctx),
        Commands::Agent { action } => handle_artifact(action, ArtifactKind::Agent, &ctx),
        Commands::Skill { action } => handle_artifact(action, ArtifactKind::Skill, &ctx),
        Commands::List => {
            let output = cmx::list::list_all_with(&ctx)?;
            print!("{}", cmx::display::format_list_all_output(&output));
            Ok(())
        }
        Commands::Info { name } => {
            let info = cmx::info::info_with(&name, &ctx)?;
            print!("{}", cmx::display::format_info(&info));
            Ok(())
        }
        Commands::Outdated => {
            let rows = cmx::outdated::outdated_with(&ctx)?;
            print!("{}", cmx::display::format_outdated(&rows));
            Ok(())
        }
        Commands::Search { query } => {
            let output = cmx::search::search_with(&query, &ctx)?;
            print!("{}", cmx::display::format_search_results(&output));
            Ok(())
        }
        Commands::Config { action } => handle_config(action, &ctx),
    }
}

fn handle_source(action: SourceAction, paths: &ConfigPaths, ctx: &AppContext<'_>) -> Result<()> {
    match action {
        SourceAction::Add { name, path_or_url } => {
            if cmx::source::looks_like_url(&path_or_url) {
                let clone_dir = paths.git_clones_dir().join(&name);
                print!("{}", cmx::display::format_source_clone_start(&path_or_url, &clone_dir));
            }
            let result = cmx::source::add_with(&name, &path_or_url, ctx)?;
            print!("{}", cmx::display::format_source_add_result(&result));
            Ok(())
        }
        SourceAction::List => {
            let result = cmx::source::list_with(ctx)?;
            print!("{}", cmx::display::format_source_list(&result));
            Ok(())
        }
        SourceAction::Browse { name } => {
            let result = cmx::source::browse_with(&name, ctx)?;
            print!("{}", cmx::display::format_browse_result(&result));
            Ok(())
        }
        SourceAction::Update { name } => {
            let output = cmx::source::update_with(name.as_deref(), ctx)?;
            print!("{}", cmx::display::format_source_update_output(&output));
            Ok(())
        }
        SourceAction::Remove { name } => {
            let result = cmx::source::remove_with(&name, ctx)?;
            print!("{}", cmx::display::format_source_remove_result(&result));
            Ok(())
        }
    }
}

fn handle_config(action: ConfigAction, ctx: &AppContext<'_>) -> Result<()> {
    match action {
        ConfigAction::Show => {
            let result = cmx::cmx_config::show_with(ctx)?;
            print!("{}", cmx::display::format_config_show(&result));
            Ok(())
        }
        ConfigAction::Gateway { value } => {
            let result = cmx::cmx_config::set_gateway_with(&value, ctx)?;
            print!("{}", cmx::display::format_config_set("gateway", &result));
            Ok(())
        }
        ConfigAction::Model { value } => {
            let result = cmx::cmx_config::set_model_with(&value, ctx)?;
            print!("{}", cmx::display::format_config_set("model", &result));
            Ok(())
        }
    }
}

fn handle_artifact(action: ArtifactAction, kind: ArtifactKind, ctx: &AppContext<'_>) -> Result<()> {
    match action {
        ArtifactAction::Install {
            name,
            all,
            local,
            force,
        } => {
            if all {
                let result = cmx::install::install_all_with(kind, local, force, ctx)?;
                print!("{}", cmx::display::format_install_all_result(&result));
                Ok(())
            } else if let Some(name) = name {
                let result = cmx::install::install_with(&name, kind, local, force, ctx)?;
                print!("{}", cmx::display::format_install_result(&result));
                Ok(())
            } else {
                bail!("Provide an artifact name or use --all")
            }
        }
        ArtifactAction::List => {
            let output = cmx::list::list_kind_with(kind, ctx)?;
            print!("{}", cmx::display::format_list_kind_output(&output));
            Ok(())
        }
        #[cfg(feature = "llm")]
        ArtifactAction::Diff { name } => {
            use cmx::gateway::real::MojenticLlmClient;
            let cfg = cmx::config::load_config_with(ctx.fs, ctx.paths)?;
            let llm = MojenticLlmClient::new(cfg.llm);
            let diff_ctx = AppContext {
                fs: ctx.fs,
                git: ctx.git,
                clock: ctx.clock,
                paths: ctx.paths,
                llm: Some(&llm),
            };
            let rt = tokio::runtime::Builder::new_current_thread().enable_all().build()?;
            let output = rt.block_on(cmx::diff::diff_with(&name, kind, &diff_ctx))?;
            print!("{}", cmx::display::format_diff_output(&output));
            Ok(())
        }
        ArtifactAction::Update { name, all, force } => {
            if all {
                let result = cmx::install::update_all_with(kind, force, ctx)?;
                print!("{}", cmx::display::format_update_all_result(&result));
                Ok(())
            } else if let Some(name) = name {
                let result = cmx::install::update_with(&name, kind, force, ctx)?;
                print!("{}", cmx::display::format_install_result(&result));
                Ok(())
            } else {
                bail!("Provide an artifact name or use --all")
            }
        }
        ArtifactAction::Uninstall { name, local } => {
            let result = cmx::uninstall::uninstall_with(&name, kind, local, ctx)?;
            print!("{}", cmx::display::format_uninstall_result(&result));
            Ok(())
        }
    }
}

use anyhow::Result;
use std::collections::{BTreeMap, BTreeSet};

use crate::checksum;
use crate::config;
use crate::context::AppContext;
use crate::lockfile;
use crate::source;
use crate::source_iter;
use crate::source_iter::SourceArtifactInfo;
use crate::types::{ArtifactKind, LockFile};

// ---------------------------------------------------------------------------
// Result types
// ---------------------------------------------------------------------------

pub struct OutdatedRow {
    pub name: String,
    pub kind: ArtifactKind,
    pub installed_version: String,
    pub available_version: String,
    pub source: String,
    pub status: String,
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

pub fn outdated_with(ctx: &AppContext<'_>) -> Result<Vec<OutdatedRow>> {
    source::auto_update_all_with(ctx)?;

    let source_artifacts = source_iter::all_with_checksums(ctx)?;

    let mut rows = Vec::new();

    let (global_lock, local_lock) = lockfile::load_both_with(ctx.fs, ctx.paths)?;
    for (local, lock) in [(false, &global_lock), (true, &local_lock)] {
        for kind in [ArtifactKind::Agent, ArtifactKind::Skill] {
            collect_outdated_for_scope_with(kind, local, lock, &source_artifacts, &mut rows, ctx)?;
        }
    }

    // Deduplicate by (name, source) in case both lock and disk scan find the same artifact
    let mut seen = BTreeSet::new();
    rows.retain(|r| seen.insert((r.name.clone(), r.source.clone())));

    Ok(rows)
}

// ---------------------------------------------------------------------------
// Private helpers
// ---------------------------------------------------------------------------

/// Returns `true` if an installed artifact is considered outdated relative to
/// the source.  Pure function — no I/O.
fn is_outdated(
    lock_entry: Option<&crate::types::LockEntry>,
    source_checksum: &str,
    source_version: Option<&str>,
) -> bool {
    match lock_entry {
        Some(entry) => {
            // Checksum changed
            if entry.source_checksum != source_checksum {
                return true;
            }
            // Installed without a version but source now has one
            if entry.version.is_none() && source_version.is_some() {
                return true;
            }
            false
        }
        // No lock entry — untracked
        None => true,
    }
}

/// Derives the human-readable status label given installed and available version
/// strings.  Pure function — no I/O.
fn outdated_status_label(installed_v: &str, available_v: &str) -> &'static str {
    if installed_v == "-" && available_v != "-" {
        "untracked"
    } else if installed_v != "-" && available_v != "-" && installed_v != available_v {
        "update"
    } else {
        "changed"
    }
}

fn collect_outdated_for_scope_with(
    kind: ArtifactKind,
    local: bool,
    lock: &LockFile,
    source_artifacts: &BTreeMap<String, Vec<SourceArtifactInfo>>,
    rows: &mut Vec<OutdatedRow>,
    ctx: &AppContext<'_>,
) -> Result<()> {
    let installed = config::installed_names_with(kind, local, ctx.fs, ctx.paths)?;

    for name in &installed {
        let lock_entry = lock.packages.get(name);
        let source_infos = source_artifacts.get(name);

        // No source artifact — nothing to compare against
        let Some(source_infos) = source_infos else {
            continue;
        };

        let installed_v = lock_entry.and_then(|e| e.version.as_deref()).unwrap_or("-").to_string();

        // Check for local modifications once (shared across all source rows)
        let locally_modified = if let Some(entry) = lock_entry {
            let install_path = kind.installed_path(name, &ctx.paths.install_dir(kind, local));
            ctx.fs.exists(&install_path)
                && checksum::is_locally_modified(&install_path, kind, entry, ctx.fs)?
        } else {
            false
        };

        for source_info in source_infos {
            let available_v = source_info.version.as_deref().unwrap_or("-").to_string();

            if !is_outdated(lock_entry, &source_info.checksum, source_info.version.as_deref()) {
                continue;
            }

            let mut status = outdated_status_label(&installed_v, &available_v).to_string();
            if locally_modified {
                status = format!("{status} (modified)");
            }

            rows.push(OutdatedRow {
                name: name.clone(),
                kind,
                installed_version: installed_v.clone(),
                available_version: available_v,
                source: source_info.source_name.clone(),
                status,
            });
        }
    }

    Ok(())
}

