use anyhow::Result;
use std::path::{Path, PathBuf};

use crate::gateway::filesystem::Filesystem;
use crate::types::{Artifact, ArtifactKind, Deprecation};

// ---------------------------------------------------------------------------
// Warning types
// ---------------------------------------------------------------------------

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct ScanWarning {
    pub message: String,
}

#[derive(Debug)]
pub struct ScanResult {
    pub artifacts: Vec<Artifact>,
    pub warnings: Vec<ScanWarning>,
}

// ---------------------------------------------------------------------------
// Testable variant (accepts injected Filesystem)
// ---------------------------------------------------------------------------

pub fn scan_source_with(root: &Path, fs: &dyn Filesystem) -> Result<ScanResult> {
    let marketplace = root.join(".claude-plugin").join("marketplace.json");
    let mut warnings = Vec::new();

    let mut artifacts = if fs.exists(&marketplace) {
        scan_marketplace_with(root, &marketplace, fs, &mut warnings)?
    } else {
        let mut arts = Vec::new();
        walk_dir_with(root, &mut arts, fs)?;
        arts
    };

    artifacts.sort_by(|a, b| a.name.cmp(&b.name));
    Ok(ScanResult {
        artifacts,
        warnings,
    })
}

fn scan_marketplace_with(
    root: &Path,
    marketplace_path: &Path,
    fs: &dyn Filesystem,
    warnings: &mut Vec<ScanWarning>,
) -> Result<Vec<Artifact>> {
    let content = fs.read_to_string(marketplace_path)?;
    let manifest: serde_json::Value = serde_json::from_str(&content)?;

    let mut artifacts = Vec::new();

    if let Some(plugins) = manifest.get("plugins").and_then(|p| p.as_array()) {
        for plugin in plugins {
            let has_agents =
                plugin.get("agents").and_then(|a| a.as_array()).is_some_and(|a| !a.is_empty());
            let has_skills =
                plugin.get("skills").and_then(|s| s.as_array()).is_some_and(|s| !s.is_empty());

            // If explicit agents/skills arrays are present, use them directly
            if has_agents || has_skills {
                scan_marketplace_explicit_arrays(root, plugin, &mut artifacts, fs, warnings);
                continue;
            }

            // Otherwise, resolve the source field and walk the directory
            if let Some(source) = plugin.get("source") {
                if let Some(source_path) = source.as_str() {
                    // Relative path source — walk the resolved directory
                    let resolved = root.join(source_path);
                    if fs.exists(&resolved) {
                        walk_dir_with(&resolved, &mut artifacts, fs)?;
                    } else {
                        let plugin_name =
                            plugin.get("name").and_then(|n| n.as_str()).unwrap_or("<unnamed>");
                        warnings.push(ScanWarning {
                            message: format!(
                                "plugin '{plugin_name}' source path '{source_path}' does not exist"
                            ),
                        });
                    }
                } else if source.is_object() {
                    // Remote source (github, url, git-subdir, npm) — not yet supported
                    let plugin_name =
                        plugin.get("name").and_then(|n| n.as_str()).unwrap_or("<unnamed>");
                    let source_type =
                        source.get("source").and_then(|s| s.as_str()).unwrap_or("unknown");
                    warnings.push(ScanWarning {
                        message: format!(
                            "plugin '{plugin_name}' uses remote source type '{source_type}' which is not yet supported"
                        ),
                    });
                }
            }
        }
    }

    Ok(artifacts)
}

fn scan_marketplace_explicit_arrays(
    root: &Path,
    plugin: &serde_json::Value,
    artifacts: &mut Vec<Artifact>,
    fs: &dyn Filesystem,
    warnings: &mut Vec<ScanWarning>,
) {
    // Scan declared agents
    if let Some(agents) = plugin.get("agents").and_then(|a| a.as_array()) {
        for agent_path in agents {
            if let Some(path_str) = agent_path.as_str() {
                let full_path = root.join(path_str);
                if !fs.exists(&full_path) {
                    warnings.push(ScanWarning {
                        message: format!(
                            "marketplace declares agent '{path_str}' but path does not exist"
                        ),
                    });
                    continue;
                }
                if let Ok(content) = fs.read_to_string(&full_path)
                    && let Some(fm) = parse_agent_frontmatter_str(&content)
                {
                    let name = full_path
                        .file_stem()
                        .map(|s| s.to_string_lossy().to_string())
                        .unwrap_or_default();
                    artifacts.push(artifact_from_frontmatter(
                        ArtifactKind::Agent,
                        name,
                        full_path,
                        fm,
                    ));
                }
            }
        }
    }

    // Scan declared skills
    if let Some(skills) = plugin.get("skills").and_then(|s| s.as_array()) {
        for skill_path in skills {
            if let Some(path_str) = skill_path.as_str() {
                let full_path = root.join(path_str);
                if !fs.exists(&full_path) {
                    warnings.push(ScanWarning {
                        message: format!(
                            "marketplace declares skill '{path_str}' but path does not exist"
                        ),
                    });
                    continue;
                }
                let skill_md = full_path.join("SKILL.md");
                if !fs.exists(&skill_md) {
                    warnings.push(ScanWarning {
                        message: format!(
                            "marketplace declares skill '{path_str}' but SKILL.md is missing"
                        ),
                    });
                    continue;
                }
                if let Ok(content) = fs.read_to_string(&skill_md)
                    && let Some(fm) = parse_frontmatter_str(&content)
                {
                    let name = full_path
                        .file_name()
                        .map(|s| s.to_string_lossy().to_string())
                        .unwrap_or_default();
                    artifacts.push(artifact_from_frontmatter(
                        ArtifactKind::Skill,
                        name,
                        full_path,
                        fm,
                    ));
                }
            }
        }
    }
}

fn walk_dir_with(dir: &Path, artifacts: &mut Vec<Artifact>, fs: &dyn Filesystem) -> Result<()> {
    let Ok(entries) = fs.read_dir(dir) else {
        return Ok(());
    };

    for entry in entries {
        let name_str = entry.file_name.clone();

        // Skip hidden directories
        if name_str.starts_with('.') {
            continue;
        }

        if entry.is_dir {
            let skill_md = entry.path.join("SKILL.md");
            if fs.exists(&skill_md)
                && let Ok(content) = fs.read_to_string(&skill_md)
                && let Some(fm) = parse_frontmatter_str(&content)
            {
                artifacts.push(artifact_from_frontmatter(
                    ArtifactKind::Skill,
                    name_str.clone(),
                    entry.path.clone(),
                    fm,
                ));
                // Don't recurse into skill directories — .md files inside
                // are reference material, not agents
            } else {
                walk_dir_with(&entry.path, artifacts, fs)?;
            }
        } else if entry.path.extension().is_some_and(|ext| ext == "md")
            && name_str != "SKILL.md"
            && dir.file_name().is_some_and(|d| d == "agents")
            && let Ok(content) = fs.read_to_string(&entry.path)
            && let Some(fm) = parse_agent_frontmatter_str(&content)
        {
            let agent_name = name_str.trim_end_matches(".md").to_string();
            artifacts.push(artifact_from_frontmatter(
                ArtifactKind::Agent,
                agent_name,
                entry.path.clone(),
                fm,
            ));
        }
    }

    Ok(())
}

// ---------------------------------------------------------------------------
// Pure frontmatter parsing (unchanged — no I/O)
// ---------------------------------------------------------------------------

struct Frontmatter {
    description: String,
    version: Option<String>,
    deprecation: Option<Deprecation>,
}

fn artifact_from_frontmatter(
    kind: ArtifactKind,
    name: String,
    path: PathBuf,
    fm: Frontmatter,
) -> Artifact {
    Artifact {
        kind,
        name,
        description: fm.description,
        path,
        version: fm.version,
        deprecation: fm.deprecation,
    }
}

fn parse_deprecation(fm_text: &str) -> Option<Deprecation> {
    let deprecated = extract_field(fm_text, "deprecated")?;
    if deprecated != "true" {
        return None;
    }
    Some(Deprecation {
        reason: extract_field(fm_text, "deprecated_reason"),
        replacement: extract_field(fm_text, "deprecated_replacement"),
    })
}

/// Split YAML frontmatter from content. Returns the text between `---` delimiters,
/// or `None` if delimiters are missing.
fn split_frontmatter_str(content: &str) -> Option<&str> {
    let rest = content.strip_prefix("---")?;
    let end = rest.find("---")?;
    Some(&rest[..end])
}

fn parse_frontmatter_str(content: &str) -> Option<Frontmatter> {
    parse_frontmatter_impl(content, &[])
}

fn parse_agent_frontmatter_str(content: &str) -> Option<Frontmatter> {
    parse_frontmatter_impl(content, &["name", "description"])
}

fn parse_frontmatter_impl(content: &str, required_fields: &[&str]) -> Option<Frontmatter> {
    let fm_text = split_frontmatter_str(content)?;
    for field in required_fields {
        if !fm_text.lines().any(|l| l.starts_with(&format!("{field}:"))) {
            return None;
        }
    }
    Some(Frontmatter {
        description: extract_field(fm_text, "description").unwrap_or_default(),
        version: extract_version(fm_text),
        deprecation: parse_deprecation(fm_text),
    })
}

pub fn extract_field(frontmatter: &str, key: &str) -> Option<String> {
    let prefix = format!("{key}:");
    frontmatter
        .lines()
        .find(|l| l.starts_with(&prefix))
        .map(|l| l[prefix.len()..].trim().trim_matches('"').to_string())
        .filter(|v| !v.is_empty())
}

/// Extract a field nested under `metadata:` in YAML frontmatter.
/// Matches indented lines (spaces or tabs) under the `metadata:` block.
pub fn extract_metadata_field(frontmatter: &str, key: &str) -> Option<String> {
    let mut in_metadata = false;
    for line in frontmatter.lines() {
        if line.starts_with("metadata:") {
            in_metadata = true;
            continue;
        }
        if in_metadata {
            let trimmed = line.trim_start();
            // A non-indented, non-empty line means we've left the metadata block
            if !line.starts_with(' ') && !line.starts_with('\t') && !trimmed.is_empty() {
                return None;
            }
            let prefix = format!("{key}:");
            if trimmed.starts_with(&prefix) {
                let value = trimmed[prefix.len()..].trim().trim_matches('"').to_string();
                if !value.is_empty() {
                    return Some(value);
                }
            }
        }
    }
    None
}

/// Extract version from frontmatter, checking root-level first then metadata block.
pub fn extract_version(frontmatter: &str) -> Option<String> {
    extract_field(frontmatter, "version").or_else(|| extract_metadata_field(frontmatter, "version"))
}

/// Extract the version from an installed artifact's file content.
/// For agents, pass the .md file content. For skills, pass the SKILL.md content.
pub fn extract_version_from_content(content: &str) -> Option<String> {
    let fm_text = split_frontmatter_str(content)?;
    extract_version(fm_text)
}

