use std::collections::BTreeMap;
use std::path::PathBuf;

use anyhow::{Context, Result, bail};

use crate::checksum;
use crate::config;
use crate::context::AppContext;
use crate::gateway::filesystem::Filesystem;
use crate::scan;
use crate::types::{Artifact, ArtifactKind, SourceEntry};

/// Checksum and metadata for a source artifact, used for update/outdated comparisons.
pub struct SourceArtifactInfo {
    pub source_name: String,
    pub version: Option<String>,
    pub checksum: String,
}

/// Scan all registered sources for all artifact kinds, computing a checksum for
/// each.  Returns a map keyed by artifact name containing all sources that
/// provide each artifact.
pub fn scan_all_with_checksums(
    sources: &BTreeMap<String, SourceEntry>,
    fs: &dyn Filesystem,
) -> Result<BTreeMap<String, Vec<SourceArtifactInfo>>> {
    let mut result: BTreeMap<String, Vec<SourceArtifactInfo>> = BTreeMap::new();

    for sa in each_source_artifact_with(sources, fs) {
        let cs = checksum::checksum_artifact_with(&sa.artifact.path, sa.artifact.kind, fs)?;
        result.entry(sa.artifact.name).or_default().push(SourceArtifactInfo {
            source_name: sa.source_name,
            version: sa.artifact.version,
            checksum: cs,
        });
    }

    Ok(result)
}

/// An artifact discovered during source scanning, with its source context.
pub struct SourceArtifact {
    pub source_name: String,
    pub source_root: PathBuf,
    pub artifact: Artifact,
}

/// Iterate over all artifacts across a set of registered sources via the given filesystem.
///
/// Resolves local paths, scans each source, and returns every artifact found
/// with its source context. Silently skips sources whose local paths do not
/// exist or that fail to scan (sources may be unavailable during normal use).
pub fn each_source_artifact_with(
    sources: &BTreeMap<String, SourceEntry>,
    fs: &dyn Filesystem,
) -> Vec<SourceArtifact> {
    let mut results = Vec::new();

    for (source_name, entry) in sources {
        let local_path = config::resolve_local_path(entry);
        if !fs.exists(&local_path) {
            continue;
        }
        if let Ok(scan_result) = scan::scan_source_with(&local_path, fs) {
            for artifact in scan_result.artifacts {
                results.push(SourceArtifact {
                    source_name: source_name.clone(),
                    source_root: local_path.clone(),
                    artifact,
                });
            }
        }
    }

    results
}

/// Load all source artifacts across every registered source via the given `AppContext`.
///
/// Convenience wrapper around `config::load_sources_with` + `each_source_artifact_with`.
pub fn all_artifacts(ctx: &AppContext<'_>) -> Result<Vec<SourceArtifact>> {
    let sources = config::load_sources_with(ctx.fs, ctx.paths)?;
    Ok(each_source_artifact_with(&sources.sources, ctx.fs))
}

/// Scan all registered sources and compute checksums for every artifact.
///
/// Convenience wrapper around `config::load_sources_with` + `scan_all_with_checksums`.
pub fn all_with_checksums(
    ctx: &AppContext<'_>,
) -> Result<BTreeMap<String, Vec<SourceArtifactInfo>>> {
    let sources = config::load_sources_with(ctx.fs, ctx.paths)?;
    scan_all_with_checksums(&sources.sources, ctx.fs)
}

/// Return all source artifacts matching the given name and kind across all registered sources.
pub fn find_by_name_and_kind(
    name: &str,
    kind: ArtifactKind,
    ctx: &AppContext<'_>,
) -> Result<Vec<SourceArtifact>> {
    Ok(all_artifacts(ctx)?
        .into_iter()
        .filter(|sa| sa.artifact.name == name && sa.artifact.kind == kind)
        .collect())
}

/// Locate exactly one artifact by name and kind across registered sources.
///
/// If `source` is `Some`, only that source is searched.  Bails with a
/// descriptive error when zero or more than one match is found.
pub fn find_unique(
    name: &str,
    kind: ArtifactKind,
    source: Option<&str>,
    ctx: &AppContext<'_>,
) -> Result<SourceArtifact> {
    let sources = config::load_sources_with(ctx.fs, ctx.paths)?;

    if sources.sources.is_empty() {
        bail!("No sources registered. Add one with: cmx source add <name> <path-or-url>");
    }

    let search_sources: BTreeMap<_, _> = if let Some(src) = source {
        let entry =
            sources.sources.get(src).with_context(|| format!("Source '{src}' not found."))?;
        std::iter::once((src.to_string(), entry.clone())).collect()
    } else {
        sources.sources.clone()
    };

    let mut found: Vec<SourceArtifact> = each_source_artifact_with(&search_sources, ctx.fs)
        .into_iter()
        .filter(|sa| sa.artifact.name == name && sa.artifact.kind == kind)
        .collect();

    if found.is_empty() {
        bail!("No {kind} named '{name}' found in registered sources.");
    }

    if found.len() > 1 {
        let source_names: Vec<_> = found.iter().map(|sa| sa.source_name.as_str()).collect();
        bail!(
            "'{name}' found in multiple sources: {}. Use <source>:{name} to disambiguate.",
            source_names.join(", ")
        );
    }

    Ok(found.remove(0))
}

