#[cfg(test)]
mod tests {
    use super::*;
    use crate::gateway::fakes::{FakeClock, FakeFilesystem, FakeGitClient};
    use crate::test_support::{make_ctx, sample_lock_entry, test_paths};
    use crate::types::{ArtifactKind, LockFile};
    use chrono::Utc;
    use std::collections::BTreeMap;

    #[test]
    fn uninstall_bails_when_agent_not_installed() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();
        let ctx = make_ctx(&fs, &git, &clock, &paths);

        let result = uninstall_with("nonexistent", ArtifactKind::Agent, false, &ctx);
        assert!(result.is_err());
        let msg = result.err().unwrap().to_string();
        assert!(msg.contains("nonexistent"), "unexpected: {msg}");
    }

    #[test]
    fn uninstall_removes_agent_file() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();

        let agent_path = paths.install_dir(ArtifactKind::Agent, false).join("my-agent.md");
        fs.add_file(agent_path.clone(), "# agent");

        let ctx = make_ctx(&fs, &git, &clock, &paths);
        uninstall_with("my-agent", ArtifactKind::Agent, false, &ctx).unwrap();

        assert!(!fs.file_exists(&agent_path), "agent file should be removed");
    }

    #[test]
    fn uninstall_removes_skill_dir() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();

        let skill_dir = paths.install_dir(ArtifactKind::Skill, false).join("my-skill");
        fs.add_file(skill_dir.join("SKILL.md"), "---\n---\n");
        fs.add_file(skill_dir.join("tool.py"), "code");

        let ctx = make_ctx(&fs, &git, &clock, &paths);
        uninstall_with("my-skill", ArtifactKind::Skill, false, &ctx).unwrap();

        assert!(!fs.file_exists(&skill_dir.join("SKILL.md")), "skill dir should be removed");
    }

    #[test]
    fn uninstall_removes_lock_entry() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();

        let agent_path = paths.install_dir(ArtifactKind::Agent, false).join("my-agent.md");
        fs.add_file(agent_path.clone(), "# agent");

        // Write a lock file with an entry
        let mut packages = BTreeMap::new();
        packages.insert("my-agent".to_string(), sample_lock_entry());
        let lock = LockFile {
            version: 1,
            packages,
        };
        lockfile::save_with(&lock, false, &fs, &paths).unwrap();

        let ctx = make_ctx(&fs, &git, &clock, &paths);
        let result = uninstall_with("my-agent", ArtifactKind::Agent, false, &ctx).unwrap();

        // Verify result fields
        assert_eq!(result.name, "my-agent");
        assert_eq!(result.kind, ArtifactKind::Agent);
        assert_eq!(result.scope, "global");
        assert!(result.was_tracked, "expected was_tracked to be true");

        let updated_lock = lockfile::load_with(false, &fs, &paths).unwrap();
        assert!(!updated_lock.packages.contains_key("my-agent"), "lock entry should be removed");
    }

    #[test]
    fn uninstall_succeeds_even_without_lock_entry() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();

        let agent_path = paths.install_dir(ArtifactKind::Agent, false).join("untracked.md");
        fs.add_file(agent_path, "# untracked agent");

        let ctx = make_ctx(&fs, &git, &clock, &paths);
        let result = uninstall_with("untracked", ArtifactKind::Agent, false, &ctx);
        assert!(result.is_ok(), "uninstall should succeed even without lock entry");

        let result = result.unwrap();
        assert!(!result.was_tracked, "expected was_tracked to be false for untracked artifact");
    }

    #[test]
    fn uninstall_with_delegates_to_perform_and_succeeds() {
        let fs = FakeFilesystem::new();
        let git = FakeGitClient::new();
        let clock = FakeClock::at(Utc::now());
        let paths = test_paths();

        let agent_path = paths.install_dir(ArtifactKind::Agent, false).join("my-agent.md");
        fs.add_file(agent_path, "# agent");

        let ctx = make_ctx(&fs, &git, &clock, &paths);
        let result = uninstall_with("my-agent", ArtifactKind::Agent, false, &ctx);
        assert!(result.is_ok(), "uninstall_with should succeed: {:?}", result.err());
    }
}

use cmx::checksum::{checksum_artifact_with, checksum_dir_with, checksum_file_with};
use cmx::gateway::real::RealFilesystem;
use cmx::types::ArtifactKind;
use std::fs;
use tempfile::TempDir;

// --- File checksum ---

#[test]
fn checksum_file_produces_sha256_prefix() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("file.md");
    fs::write(&path, b"hello world").unwrap();
    let cs = checksum_file_with(&path, &RealFilesystem).unwrap();
    assert!(cs.starts_with("sha256:"), "expected sha256: prefix, got: {cs}");
}

#[test]
fn checksum_file_is_deterministic() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("file.md");
    fs::write(&path, b"deterministic content").unwrap();
    let cs1 = checksum_file_with(&path, &RealFilesystem).unwrap();
    let cs2 = checksum_file_with(&path, &RealFilesystem).unwrap();
    assert_eq!(cs1, cs2);
}

#[test]
fn checksum_file_differs_for_different_content() {
    let dir = TempDir::new().unwrap();
    let path_a = dir.path().join("a.md");
    let path_b = dir.path().join("b.md");
    fs::write(&path_a, b"content A").unwrap();
    fs::write(&path_b, b"content B").unwrap();
    let cs_a = checksum_file_with(&path_a, &RealFilesystem).unwrap();
    let cs_b = checksum_file_with(&path_b, &RealFilesystem).unwrap();
    assert_ne!(cs_a, cs_b);
}

#[test]
fn checksum_file_same_content_same_checksum() {
    let dir = TempDir::new().unwrap();
    let path_a = dir.path().join("a.md");
    let path_b = dir.path().join("b.md");
    let content = b"identical content";
    fs::write(&path_a, content).unwrap();
    fs::write(&path_b, content).unwrap();
    let cs_a = checksum_file_with(&path_a, &RealFilesystem).unwrap();
    let cs_b = checksum_file_with(&path_b, &RealFilesystem).unwrap();
    assert_eq!(cs_a, cs_b);
}

// --- Directory checksum ---

#[test]
fn checksum_dir_is_deterministic() {
    let dir = TempDir::new().unwrap();
    fs::write(dir.path().join("SKILL.md"), b"# Skill\n").unwrap();
    fs::write(dir.path().join("prompt.md"), b"# Prompt\n").unwrap();

    let cs1 = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();
    let cs2 = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(cs1, cs2);
}

#[test]
fn checksum_dir_changes_when_file_content_changes() {
    let dir = TempDir::new().unwrap();
    let file = dir.path().join("SKILL.md");
    fs::write(&file, b"# Original\n").unwrap();

    let cs_before = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();
    fs::write(&file, b"# Modified\n").unwrap();
    let cs_after = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();

    assert_ne!(cs_before, cs_after);
}

#[test]
fn checksum_dir_excludes_dotfiles() {
    let dir = TempDir::new().unwrap();
    fs::write(dir.path().join("SKILL.md"), b"# Skill\n").unwrap();

    let cs_without = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();

    // Add a dotfile — checksum must not change
    fs::write(dir.path().join(".DS_Store"), b"mac metadata").unwrap();
    let cs_with = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();

    assert_eq!(cs_without, cs_with, "dotfiles must not affect the directory checksum");
}

#[test]
fn checksum_dir_changes_when_new_file_added() {
    let dir = TempDir::new().unwrap();
    fs::write(dir.path().join("SKILL.md"), b"# Skill\n").unwrap();

    let cs_before = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();
    fs::write(dir.path().join("extra.md"), b"# Extra\n").unwrap();
    let cs_after = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();

    assert_ne!(cs_before, cs_after);
}

// --- checksum_artifact dispatch ---

#[test]
fn checksum_artifact_agent_dispatches_to_checksum_file() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("my-agent.md");
    fs::write(&path, b"# Agent\n").unwrap();

    let via_artifact = checksum_artifact_with(&path, ArtifactKind::Agent, &RealFilesystem).unwrap();
    let via_file = checksum_file_with(&path, &RealFilesystem).unwrap();

    assert_eq!(via_artifact, via_file, "checksum_artifact(Agent) must match checksum_file");
}

#[test]
fn checksum_artifact_skill_dispatches_to_checksum_dir() {
    let dir = TempDir::new().unwrap();
    fs::write(dir.path().join("SKILL.md"), b"# Skill\n").unwrap();
    fs::write(dir.path().join("prompt.md"), b"# Prompt\n").unwrap();

    let via_artifact =
        checksum_artifact_with(dir.path(), ArtifactKind::Skill, &RealFilesystem).unwrap();
    let via_dir = checksum_dir_with(dir.path(), &RealFilesystem).unwrap();

    assert_eq!(via_artifact, via_dir, "checksum_artifact(Skill) must match checksum_dir");
}

use cmx::gateway::real::RealFilesystem;
use cmx::lockfile::{load_from_with, save_to_with};
use cmx::types::{ArtifactKind, LockEntry, LockFile, LockSource};
use std::collections::BTreeMap;
use tempfile::TempDir;

fn sample_lock_file() -> LockFile {
    let mut packages = BTreeMap::new();
    packages.insert(
        "rust-craftsperson".to_string(),
        LockEntry {
            artifact_type: ArtifactKind::Agent,
            version: Some("1.0.0".to_string()),
            installed_at: "2024-01-01T00:00:00Z".to_string(),
            source: LockSource {
                repo: "guidelines".to_string(),
                path: "agents/rust-craftsperson.md".to_string(),
            },
            source_checksum: "sha256:abc123".to_string(),
            installed_checksum: "sha256:def456".to_string(),
        },
    );
    LockFile {
        version: 1,
        packages,
    }
}

#[test]
fn save_and_load_round_trips_all_fields() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("cmx-lock.json");

    let original = sample_lock_file();
    save_to_with(&original, &path, &RealFilesystem).unwrap();
    let restored = load_from_with(&path, &RealFilesystem).unwrap();

    assert_eq!(restored.version, original.version);
    let entry = restored.packages.get("rust-craftsperson").expect("entry present");
    assert_eq!(entry.version.as_deref(), Some("1.0.0"));
    assert_eq!(entry.source.repo, "guidelines");
    assert_eq!(entry.source.path, "agents/rust-craftsperson.md");
    assert_eq!(entry.source_checksum, "sha256:abc123");
    assert_eq!(entry.installed_checksum, "sha256:def456");
    assert_eq!(entry.artifact_type, ArtifactKind::Agent);
}

