#[test]
fn write_then_read_to_string_round_trip() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("hello.txt");
    fs().write(&path, "hello world").unwrap();
    let content = fs().read_to_string(&path).unwrap();
    assert_eq!(content, "hello world");
}

#[test]
fn write_bytes_then_read_round_trip() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("bytes.bin");
    let data: Vec<u8> = vec![1, 2, 3, 255];
    fs().write_bytes(&path, &data).unwrap();
    let result = fs().read(&path).unwrap();
    assert_eq!(result, data);
}

#[test]
fn exists_false_for_missing_path() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("nonexistent.txt");
    assert!(!fs().exists(&path));
}

#[test]
fn exists_true_after_write() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("present.txt");
    fs().write(&path, "content").unwrap();
    assert!(fs().exists(&path));
}

#[test]
fn is_file_true_for_file_false_for_dir() {
    let dir = TempDir::new().unwrap();
    let file_path = dir.path().join("a.txt");
    fs().write(&file_path, "x").unwrap();
    assert!(fs().is_file(&file_path));
    assert!(!fs().is_file(dir.path()));
}

#[test]
fn is_dir_true_for_dir_false_for_file() {
    let dir = TempDir::new().unwrap();
    let file_path = dir.path().join("a.txt");
    fs().write(&file_path, "x").unwrap();
    assert!(fs().is_dir(dir.path()));
    assert!(!fs().is_dir(&file_path));
}

#[test]
fn create_dir_all_creates_nested_directories() {
    let dir = TempDir::new().unwrap();
    let nested = dir.path().join("a").join("b").join("c");
    fs().create_dir_all(&nested).unwrap();
    assert!(nested.is_dir());
}

#[test]
fn copy_file_copies_content_accurately() {
    let dir = TempDir::new().unwrap();
    let src = dir.path().join("src.txt");
    let dest = dir.path().join("dest.txt");
    fs::write(&src, b"original content").unwrap();
    fs().copy_file(&src, &dest).unwrap();
    let copied = fs::read_to_string(&dest).unwrap();
    assert_eq!(copied, "original content");
}

#[test]
fn remove_file_removes_file_and_exists_returns_false() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("to_remove.txt");
    fs().write(&path, "data").unwrap();
    assert!(fs().exists(&path));
    fs().remove_file(&path).unwrap();
    assert!(!fs().exists(&path));
}

#[test]
fn remove_dir_all_removes_directory_tree() {
    let dir = TempDir::new().unwrap();
    let sub = dir.path().join("subdir");
    fs::create_dir(&sub).unwrap();
    fs::write(sub.join("file.txt"), b"data").unwrap();
    assert!(sub.exists());
    fs().remove_dir_all(&sub).unwrap();
    assert!(!sub.exists());
}

#[test]
fn read_dir_lists_children_with_correct_metadata() {
    let dir = TempDir::new().unwrap();
    fs::write(dir.path().join("alpha.md"), b"a").unwrap();
    fs::write(dir.path().join("beta.md"), b"b").unwrap();
    let sub = dir.path().join("subdir");
    fs::create_dir(&sub).unwrap();

    let mut entries = fs().read_dir(dir.path()).unwrap();
    entries.sort_by(|a, b| a.file_name.cmp(&b.file_name));

    let names: Vec<&str> = entries.iter().map(|e| e.file_name.as_str()).collect();
    assert!(names.contains(&"alpha.md"), "alpha.md missing from {names:?}");
    assert!(names.contains(&"beta.md"), "beta.md missing from {names:?}");
    assert!(names.contains(&"subdir"), "subdir missing from {names:?}");

    let subdir_entry = entries.iter().find(|e| e.file_name == "subdir").unwrap();
    assert!(subdir_entry.is_dir);

    let file_entry = entries.iter().find(|e| e.file_name == "alpha.md").unwrap();
    assert!(!file_entry.is_dir);
}

#[test]
fn canonicalize_resolves_real_path_without_error() {
    let dir = TempDir::new().unwrap();
    let path = dir.path().join("file.txt");
    fs::write(&path, b"x").unwrap();
    let canonical = fs().canonicalize(&path).unwrap();
    assert!(canonical.is_absolute());
}

#[test]
fn read_to_string_on_missing_file_returns_error() {
    let dir = TempDir::new().unwrap();
    let missing = dir.path().join("does_not_exist.txt");
    let result = fs().read_to_string(&missing);
    assert!(result.is_err());
}

use cmx::gateway::real::RealFilesystem;
use cmx::scan::scan_source_with;
use cmx::types::ArtifactKind;
use std::fs;
use tempfile::TempDir;

fn write_file(dir: &std::path::Path, name: &str, content: &str) {
    fs::write(dir.join(name), content).expect("write file");
}

fn agent_frontmatter(name: &str, description: &str) -> String {
    format!("---\nname: {name}\ndescription: {description}\n---\n\n# {name}\n")
}

fn skill_frontmatter(description: &str) -> String {
    format!("---\ndescription: {description}\n---\n\n# Skill\n")
}

// --- Walk-based scan (no marketplace.json) ---

#[test]
fn scan_empty_directory_returns_empty() {
    let dir = TempDir::new().unwrap();
    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert!(result.artifacts.is_empty());
}

#[test]
fn scan_finds_agent_with_valid_frontmatter() {
    let dir = TempDir::new().unwrap();
    let agents_dir = dir.path().join("agents");
    fs::create_dir_all(&agents_dir).unwrap();
    write_file(&agents_dir, "my-agent.md", &agent_frontmatter("my-agent", "Does something"));
    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 1);
    assert_eq!(result.artifacts[0].name, "my-agent");
    assert_eq!(result.artifacts[0].description, "Does something");
    assert_eq!(result.artifacts[0].kind, ArtifactKind::Agent);
}

#[test]
fn scan_ignores_md_file_without_agent_frontmatter() {
    let dir = TempDir::new().unwrap();
    // Missing "name:" field — not an agent
    write_file(dir.path(), "readme.md", "---\ndescription: Just a readme\n---\n# Readme\n");
    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert!(result.artifacts.is_empty(), "expected empty, got {:?}", result.artifacts);
}

#[test]
fn scan_ignores_md_file_without_any_frontmatter() {
    let dir = TempDir::new().unwrap();
    write_file(dir.path(), "notes.md", "# Notes\n\nJust notes.\n");
    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert!(result.artifacts.is_empty());
}

#[test]
fn scan_finds_skill_with_skill_md() {
    let dir = TempDir::new().unwrap();
    let skill_dir = dir.path().join("my-skill");
    fs::create_dir_all(&skill_dir).unwrap();
    write_file(&skill_dir, "SKILL.md", &skill_frontmatter("A useful skill"));
    write_file(&skill_dir, "prompt.md", "# Prompt\n");

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 1);
    assert_eq!(result.artifacts[0].name, "my-skill");
    assert_eq!(result.artifacts[0].description, "A useful skill");
    assert_eq!(result.artifacts[0].kind, ArtifactKind::Skill);
}

#[test]
fn scan_skips_hidden_directories() {
    let dir = TempDir::new().unwrap();
    let hidden = dir.path().join(".hidden");
    fs::create_dir_all(&hidden).unwrap();
    write_file(&hidden, "secret-agent.md", &agent_frontmatter("secret-agent", "Hidden"));

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert!(result.artifacts.is_empty(), "hidden dirs must be skipped");
}

#[test]
fn scan_finds_multiple_agents_sorted_by_name() {
    let dir = TempDir::new().unwrap();
    let agents_dir = dir.path().join("agents");
    fs::create_dir_all(&agents_dir).unwrap();
    write_file(&agents_dir, "zebra.md", &agent_frontmatter("zebra", "Last"));
    write_file(&agents_dir, "alpha.md", &agent_frontmatter("alpha", "First"));
    write_file(&agents_dir, "middle.md", &agent_frontmatter("middle", "Middle"));

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 3);
    let names: Vec<_> = result.artifacts.iter().map(|a| a.name.as_str()).collect();
    assert_eq!(names, ["alpha", "middle", "zebra"]);
}

#[test]
fn scan_finds_both_agents_and_skills() {
    let dir = TempDir::new().unwrap();
    let agents_dir = dir.path().join("agents");
    fs::create_dir_all(&agents_dir).unwrap();
    write_file(&agents_dir, "agent.md", &agent_frontmatter("agent", "An agent"));
    let skill_dir = dir.path().join("skill");
    fs::create_dir_all(&skill_dir).unwrap();
    write_file(&skill_dir, "SKILL.md", &skill_frontmatter("A skill"));

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 2);
    let kinds: Vec<_> = result.artifacts.iter().map(|a| a.kind).collect();
    assert!(kinds.contains(&ArtifactKind::Agent));
    assert!(kinds.contains(&ArtifactKind::Skill));
}

// --- Marketplace scan (with .claude-plugin/marketplace.json) ---

#[test]
fn scan_marketplace_finds_declared_agents() {
    let dir = TempDir::new().unwrap();

    // Write an agent file
    write_file(dir.path(), "my-agent.md", &agent_frontmatter("my-agent", "Marketplace agent"));

    // Write marketplace manifest
    let plugin_dir = dir.path().join(".claude-plugin");
    fs::create_dir_all(&plugin_dir).unwrap();
    let manifest = serde_json::json!({
        "plugins": [{
            "agents": ["my-agent.md"],
            "skills": []
        }]
    });
    fs::write(plugin_dir.join("marketplace.json"), manifest.to_string()).unwrap();

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 1);
    assert_eq!(result.artifacts[0].name, "my-agent");
    assert_eq!(result.artifacts[0].kind, ArtifactKind::Agent);
}

#[test]
fn scan_marketplace_finds_declared_skills() {
    let dir = TempDir::new().unwrap();

    // Write a skill directory
    let skill_dir = dir.path().join("my-skill");
    fs::create_dir_all(&skill_dir).unwrap();
    write_file(&skill_dir, "SKILL.md", &skill_frontmatter("Marketplace skill"));

    // Write marketplace manifest
    let plugin_dir = dir.path().join(".claude-plugin");
    fs::create_dir_all(&plugin_dir).unwrap();
    let manifest = serde_json::json!({
        "plugins": [{
            "agents": [],
            "skills": ["my-skill"]
        }]
    });
    fs::write(plugin_dir.join("marketplace.json"), manifest.to_string()).unwrap();

    let result = scan_source_with(dir.path(), &RealFilesystem).unwrap();
    assert_eq!(result.artifacts.len(), 1);
    assert_eq!(result.artifacts[0].name, "my-skill");
    assert_eq!(result.artifacts[0].kind, ArtifactKind::Skill);
}
